68:     public Response healthCheck() throws Throwable {
69:         WorkerStatus workerStatus;
70:         int statusCode;
71:         try {
72:             FutureCallback<Void> cb = new FutureCallback<>();
73:             herder.healthCheck(cb);
74: 
75:             long timeoutNs = TimeUnit.MILLISECONDS.toNanos(requestTimeout.healthCheckTimeoutMs());
76:             long deadlineNs = timeoutNs + time.nanoseconds();
77:             time.waitForFuture(cb, deadlineNs);
78: 
79:             statusCode = Response.Status.OK.getStatusCode();
80:             workerStatus = WorkerStatus.healthy();
81:         } catch (TimeoutException e) {
82:             String statusDetails = e instanceof StagedTimeoutException
83:                     ? ((StagedTimeoutException) e).stage().summarize()
84:                     : null;
85:             if (!herder.isReady()) {
86:                 statusCode = Response.Status.SERVICE_UNAVAILABLE.getStatusCode();
87:                 workerStatus = WorkerStatus.starting(statusDetails);
88:             } else {
89:                 statusCode = Response.Status.INTERNAL_SERVER_ERROR.getStatusCode();
90:                 workerStatus = WorkerStatus.unhealthy(statusDetails);
91:             }
92:         } catch (ExecutionException e) {
93:             throw e.getCause();
94:         }
95: 
96:         return Response.status(statusCode).entity(workerStatus).build();
97:     }
